public class Bar {
    private double offset = 0;
    public void measure() {
        long start = System.currentTimeMillis();
        final double initialOffset = offset;
        offset += Math.random() * 1;
        offset += Math.random() * 2;
        offset += Math.random() * 3;
        offset += Math.random() * 4;
        offset += Math.random() * 5;
        offset += Math.random() * 6;
        offset += Math.random() * 7;
        System.out.println(System.currentTimeMillis() - start);
        System.out.println(offset - initialOffset);
    }
}

